# Ze BGP configuration
# Edit via ze config edit over SSH

environment {
    log {
        level info
    }

    web {
        enabled true
        server default {
            ip 0.0.0.0
            port 8080
        }
    }

    ssh {
        enabled true
        server default {
            ip 0.0.0.0
            port 22
        }
    }

    ntp {
        enabled true
        server pool0 {
            address 0.pool.ntp.org
        }
        server pool1 {
            address 1.pool.ntp.org
        }
    }
}

interface {
    dhcp-auto true
}
